namespace sv_4b3c2f9ef21a49bfba98a351c15fbe44.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@* Reusable message input with textarea and send button *@

<div class="message-input">
    <textarea @bind="Text" @bind:event="oninput" placeholder="@Placeholder"
              @onkeydown="HandleKeyDown" rows="2"></textarea>
    <button class="send-btn" @onclick="Submit" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonText
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message...";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSubmit { get; set; }

    private string Text { get; set; } = string.Empty;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await Submit();
        }
    }

    private async Task Submit()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var message = Text.Trim();
        Text = string.Empty;
        await OnSubmit.InvokeAsync(message);
    }
}

@* Displays a single message with reactions, hover actions, and thread indicator *@

<div class="message-item @(IsHovered ? "hovered" : "")"
     @onmouseenter="() => IsHovered = true"
     @onmouseleave="() => IsHovered = false">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync(reaction.Emoji)"
                        title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync()">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (IsHovered)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync()" title="Reply in thread">
                💬 Reply
            </button>
            <div class="emoji-picker-wrapper">
                <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                    😀 React
                </button>
                @if (ShowEmojiPicker)
                {
                    <div class="emoji-picker">
                        @foreach (var emoji in CommonEmojis)
                        {
                            <button class="emoji-option" @onclick="() => SelectEmoji(emoji)">@emoji</button>
                        }
                    </div>
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnReact { get; set; }

    private bool IsHovered { get; set; }
    private bool ShowEmojiPicker { get; set; }

    private static readonly string[] CommonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => ShowEmojiPicker = !ShowEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        ShowEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@* Left sidebar showing the list of channels *@

<div class="channel-list">
    <h3 class="channel-list-header">Channels</h3>
    @foreach (var channel in Channels)
    {
        <div class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
             @onclick="() => OnChannelSelected.InvokeAsync(channel)">
            <div class="channel-name">
                <span># @channel.Name</span>
                @if (channel.UnreadCount > 0)
                {
                    <span class="unread-badge">@channel.UnreadCount</span>
                }
            </div>
            @if (!string.IsNullOrEmpty(channel.Description))
            {
                <div class="channel-description">@TruncateDescription(channel.Description)</div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<Channel> OnChannelSelected { get; set; }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "..." : description;
    }
}

@* Right panel showing thread replies for a root message *@

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose">✕</button>
    </div>

    <div class="thread-root-message">
        <span class="author">@RootMessage.Author</span>
        <p class="content">@RootMessage.Content</p>
    </div>

    <div class="thread-divider">
        <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
    </div>

    <div class="thread-messages">
        @foreach (var message in ThreadMessages)
        {
            <div class="thread-reply">
                <div class="reply-header">
                    <span class="author">@message.Author</span>
                    <span class="timestamp">@FormatRelativeTime(message.SentAt)</span>
                </div>
                <div class="reply-content">@message.Content</div>
            </div>
        }
    </div>

    <MessageInput Placeholder="Reply in thread..." ButtonText="Reply" OnSubmit="OnReply" />
</div>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@* Main message area with channel header, scrollable messages, and input *@

<div class="message-area">
    <div class="message-area-header">
        <h2># @ChannelName</h2>
        <p>@ChannelDescription</p>
    </div>

    <div class="message-list" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages...</div>
        }

        @if (CanLoadMore)
        {
            <button class="load-more-btn" @onclick="OnLoadMore">Load older messages</button>
        }

        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ReplyCount="GetReplyCount(message.Id)"
                         OnOpenThread="() => OnOpenThread.InvokeAsync(message)"
                         OnReact="(emoji) => OnReact.InvokeAsync((message.Id, emoji))" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")" OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter] public string ChannelName { get; set; } = string.Empty;
    [Parameter] public string ChannelDescription { get; set; } = string.Empty;
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool CanLoadMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }

    private int GetReplyCount(int messageId)
    {
        return ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;
    }

    private async Task HandleScroll()
    {
        // Scroll-to-top detection is handled via JS interop in production;
        // the Load More button provides a fallback for loading older messages.
    }
}

