@* Right panel showing thread replies for a root message *@

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose">✕</button>
    </div>

    <div class="thread-root-message">
        <span class="author">@RootMessage.Author</span>
        <p class="content">@RootMessage.Content</p>
    </div>

    <div class="thread-divider">
        <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
    </div>

    <div class="thread-messages">
        @foreach (var message in ThreadMessages)
        {
            <div class="thread-reply">
                <div class="reply-header">
                    <span class="author">@message.Author</span>
                    <span class="timestamp">@FormatRelativeTime(message.SentAt)</span>
                </div>
                <div class="reply-content">@message.Content</div>
            </div>
        }
    </div>

    <MessageInput Placeholder="Reply in thread..." ButtonText="Reply" OnSubmit="OnReply" />
</div>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@* Main message area with channel header, scrollable messages, and input *@

<div class="message-area">
    <div class="message-area-header">
        <h2># @ChannelName</h2>
        <p>@ChannelDescription</p>
    </div>

    <div class="message-list" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages...</div>
        }

        @if (CanLoadMore)
        {
            <button class="load-more-btn" @onclick="OnLoadMore">Load older messages</button>
        }

        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ReplyCount="GetReplyCount(message.Id)"
                         OnOpenThread="() => OnOpenThread.InvokeAsync(message)"
                         OnReact="(emoji) => OnReact.InvokeAsync((message.Id, emoji))" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")" OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter] public string ChannelName { get; set; } = string.Empty;
    [Parameter] public string ChannelDescription { get; set; } = string.Empty;
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool CanLoadMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }

    private int GetReplyCount(int messageId)
    {
        return ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;
    }

    private async Task HandleScroll()
    {
        // Scroll-to-top detection is handled via JS interop in production;
        // the Load More button provides a fallback for loading older messages.
    }
}

