namespace sv_4b3c2f9ef21a49bfba98a351c15fbe44.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@using sv_4b3c2f9ef21a49bfba98a351c15fbe44.Services
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Team Chat</PageTitle>

<div class="chat-layout @(threadOpen ? "thread-open" : "")">
    <div class="sidebar">
        <ChannelList Channels="channels"
                     SelectedChannelId="selectedChannel?.Id ?? 0"
                     OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-area">
        @if (selectedChannel is not null)
        {
            <MessageArea ChannelName="@selectedChannel.Name"
                         ChannelDescription="@selectedChannel.Description"
                         Messages="messages"
                         ThreadReplyCounts="threadReplyCounts"
                         IsLoadingMore="isLoadingMore"
                         CanLoadMore="canLoadMore"
                         OnLoadMore="LoadMoreMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (threadOpen && threadRootMessage is not null)
    {
        <div class="thread-area">
            <ThreadPanel RootMessage="threadRootMessage"
                         ThreadMessages="threadMessages"
                         OnClose="CloseThread"
                         OnReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<Message> threadMessages = [];
    private Dictionary<int, int> threadReplyCounts = [];
    private Channel? selectedChannel;
    private Message? threadRootMessage;
    private bool threadOpen;
    private bool isLoadingMore;
    private bool canLoadMore = true;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        selectedChannel = channel;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        canLoadMore = messages.Count >= PageSize;
        threadReplyCounts = BuildReplyCounts(messages);
        CloseThread();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channels to update unread counts
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore || selectedChannel is null) return;

        isLoadingMore = true;
        var olderMessages = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
        canLoadMore = olderMessages.Count >= PageSize;
        messages.InsertRange(0, olderMessages);
        threadReplyCounts = BuildReplyCounts(messages);
        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;
        var newMessage = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(newMessage);
    }

    private async Task OpenThread(Message rootMessage)
    {
        threadRootMessage = rootMessage;
        threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        threadOpen = true;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (selectedChannel is null || threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadMessages.Add(reply);

        // Update reply count
        threadReplyCounts[threadRootMessage.Id] = threadMessages.Count;
    }

    private async Task HandleReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);

        // Refresh messages to show updated reactions
        if (selectedChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, messages.Count);
        }
    }

    private static Dictionary<int, int> BuildReplyCounts(List<Message> msgs)
    {
        var counts = new Dictionary<int, int>();
        foreach (var msg in msgs)
        {
            if (msg.ReplyToId is int rootId)
            {
                counts[rootId] = counts.GetValueOrDefault(rootId) + 1;
            }
        }
        return counts;
    }
}

