{"file_text": ".chat-layout {
    display: grid;
    grid-template-columns: 240px 1fr;
    height: 100vh;
    overflow: hidden;
}

.chat-layout.thread-open {
    grid-template-columns: 240px 1fr 320px;
}

/* Sidebar */
.sidebar {
    background: #2b2d31;
    color: #f2f3f5;
    overflow-y: auto;
    border-right: 1px solid #1e1f22;
}

::deep .channel-list {
    padding: 8px 0;
}

::deep .channel-list-header {
    padding: 12px 16px 8px;
    font-size: 0.75rem;
    text-transform: uppercase;
    color: #949ba4;
    letter-spacing: 0.02em;
}

::deep .channel-item {
    padding: 6px 16px;
    cursor: pointer;
    border-radius: 4px;
    margin: 0 8px;
    transition: background 0.1s;
}

::deep .channel-item:hover {
    background: #35373c;
}

::deep .channel-item.active {
    background: #404249;
}

::deep .channel-name {
    display: flex;
    align-items: center;
    justify-content: space-between;
    font-weight: 500;
    font-size: 0.95rem;
}

::deep .unread-badge {
