.main-area {
    display: flex;
    flex-direction: column;
    background: #313338;
    color: #dbdee1;
    overflow: hidden;
}

::deep .message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
}

::deep .message-area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #3f4147;
    flex-shrink: 0;
}

::deep .message-area-header h2 {
    margin: 0;
    font-size: 1rem;
    color: #f2f3f5;
}

::deep .message-area-header p {
    margin: 2px 0 0;
    font-size: 0.8rem;
