    padding: 16px 20px;
}

::deep .loading-indicator,
::deep .load-more-btn {
    text-align: center;
    padding: 8px;
    color: #949ba4;
    font-size: 0.8rem;
}

::deep .load-more-btn {
    background: none;
    border: 1px solid #4e5058;
    border-radius: 4px;
    cursor: pointer;
    margin: 0 auto 12px;
    display: block;
    color: #00a8fc;
}

::deep .load-more-btn:hover {
    background: #35373c;
}

