    border: 1px solid #4e5058;
    border-radius: 4px;
    padding: 2px 6px;
    font-size: 0.8rem;
    cursor: pointer;
    color: #dbdee1;
}

::deep .reaction-badge:hover {
    border-color: #00a8fc;
    background: #1a3a4a;
}

::deep .thread-link {
    background: none;
    border: none;
    color: #00a8fc;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0;
    font-weight: 500;
}

::deep .thread-link:hover {
    text-decoration: underline;
}

